const items = $input.all();
const hoy = new Date();
hoy.setHours(0, 0, 0, 0);
const urgentes = [];
const proximas = [];

for (const item of items) {
  const d = item.json;

  // Solo convocatorias procesadas por IA con fecha límite
  if (d.Procesado_IA !== 'VERDADERO') continue;
  if (!d.Fecha_Limite || d.Fecha_Limite === '') continue;
  // Saltar las que ya están alertadas
  if (d.Estado === 'alertada') continue;

  // Parsear fecha límite
  let fechaLimite;
  try {
    fechaLimite = new Date(d.Fecha_Limite);
    if (isNaN(fechaLimite)) continue;
  } catch(e) { continue; }

  fechaLimite.setHours(0, 0, 0, 0);
  const diasRestantes = Math.round((fechaLimite - hoy) / (1000 * 60 * 60 * 24));

  // Descartar vencidas
  if (diasRestantes < 0) continue;

  const convocatoria = {
    id: d.ID || '',
    nombre: d.Nombre || 'Sin nombre',
    donante: d.Donante || 'Desconocido',
    fecha_limite: d.Fecha_Limite,
    monto: d.Monto || 'No especificado',
    url: d.URL || '',
    dias_restantes: diasRestantes,
    estado: d.Estado || ''
  };

  if (diasRestantes <= 15) {
    convocatoria.urgencia = '🔴 URGENTE';
    urgentes.push(convocatoria);
  } else if (diasRestantes <= 30) {
    convocatoria.urgencia = '🟡 PRÓXIMA';
    proximas.push(convocatoria);
  }
}

// Si no hay nada que alertar, salir
if (urgentes.length === 0 && proximas.length === 0) {
  return [{ json: { hay_alertas: false, urgentes: [], proximas: [], total: 0 } }];
}

return [{ json: {
  hay_alertas: true,
  urgentes,
  proximas,
  total: urgentes.length + proximas.length,
  fecha_reporte: hoy.toISOString().split('T')[0]
}}];

const d = $input.first().json;

// Construir mensaje Telegram (Markdown)
let msg = `*🔔 FundingFlow — Alertas del día ${d.fecha_reporte}*\n`;
msg += `Total convocatorias con plazo próximo: *${d.total}*\n\n`;

if (d.urgentes.length > 0) {
  msg += `*🔴 URGENTES (menos de 15 días)*\n`;
  for (const c of d.urgentes) {
   msg += `\n• *${c.nombre}*\n`;
msg += `  🏛️ Donante: ${c.donante || 'No especificado'}\n`;
msg += `  💰 Monto: ${c.monto || 'No especificado'}\n`;
msg += `  📅 Fecha límite: ${c.fecha_limite} (${c.dias_restantes} días)\n`;
msg += `  🌍 Región: Global\n`;
msg += `  📊 Estado: ${c.estado || 'en_análisis'}\n`;
if (c.url) msg += `  🔗 <a href="${c.url}">Ver convocatoria</a>\n`;
  }
}

if (d.proximas.length > 0) {
  msg += `\n*🟡 PRÓXIMAS (15-30 días)*\n`;
  for (const c of d.proximas) {
    msg += `\n• *${c.nombre}*\n`;
msg += `  🏛️ Donante: ${c.donante || 'No especificado'}\n`;
msg += `  💰 Monto: ${c.monto || 'No especificado'}\n`;
msg += `  📅 Fecha límite: ${c.fecha_limite} (${c.dias_restantes} días)\n`;
msg += `  🌍 Región: Global\n`;
msg += `  📊 Estado: ${c.estado || 'en_análisis'}\n`;
if (c.url) msg += `  🔗 [Ver convocatoria](${c.url})\n`;
  }
}

msg += `\n_FundingFlow · ${new Date().toLocaleString('es-ES')}_`;

// Truncar a 4096 chars (límite Telegram)
const msgTruncado = msg.length > 4000 ? msg.substring(0, 4000) + '...\n_(mensaje truncado)_' : msg;

// Construir mensaje Slack (texto plano con bloques)
let slackText = `*🔔 FundingFlow — Alertas ${d.fecha_reporte}* | ${d.total} convocatorias próximas\n\n`;

if (d.urgentes.length > 0) {
  slackText += `*🔴 URGENTES (< 15 días)*\n`;
  for (const c of d.urgentes) {
    slackText += `• *${c.nombre}*\n`;
slackText += `  🏛️ ${c.donante || 'No especificado'} | 💰 ${c.monto || 'No especificado'} | 📅 ${c.fecha_limite} (${c.dias_restantes} días) | 📊 ${c.estado || 'en_análisis'} | <${c.url}|Ver>\n\n`;
  }
}
if (d.proximas.length > 0) {
  slackText += `\n*🟡 PRÓXIMAS (15-30 días)*\n`;
  for (const c of d.proximas) {
    slackText += `• *${c.nombre}*\n`;
slackText += `  🏛️ ${c.donante || 'No especificado'} | 💰 ${c.monto || 'No especificado'} | 📅 ${c.fecha_limite} (${c.dias_restantes} días) | 📊 ${c.estado || 'en_análisis'} | <${c.url}|Ver>\n\n`;
  }
}

// Construir cuerpo Gmail HTML
let html = `<h2>🔔 FundingFlow — Alertas del ${d.fecha_reporte}</h2>`;
html += `<p><strong>${d.total} convocatorias con plazo próximo</strong></p>`;

if (d.urgentes.length > 0) {
  html += `<h3 style="color:#cc0000">🔴 URGENTES — Menos de 15 días</h3><table border="1" cellpadding="6" style="border-collapse:collapse;width:100%">`;
  html += `<tr style="background:#f2f2f2"><th>Nombre</th><th>🏛️ Donante</th><th>📅 Fecha límite</th><th>Días</th><th>💰 Monto</th><th>📊 Estado</th><th>🌍 Región</th><th>Enlace</th></tr>`;
  for (const c of d.urgentes) {
    html += `<tr><td>${c.nombre}</td><td>${c.donante || 'No especificado'}</td><td>${c.fecha_limite}</td><td style="color:#cc0000"><strong>${c.dias_restantes}</strong></td><td>${c.monto || 'No especificado'}</td><td>${c.estado || 'en_análisis'}</td><td>Global</td><td><a href="${c.url}" style="color:#0066cc">Ver convocatoria</a></td></tr>`;
  }
  html += `</table>`;
}

if (d.proximas.length > 0) {
  html += `<h3 style="color:#cc7700">🟡 PRÓXIMAS — 15 a 30 días</h3><table border="1" cellpadding="6" style="border-collapse:collapse;width:100%">`;
  html += `<tr style="background:#f2f2f2"><th>Nombre</th><th>🏛️ Donante</th><th>📅 Fecha límite</th><th>Días</th><th>💰 Monto</th><th>📊 Estado</th><th>🌍 Región</th><th>Enlace</th></tr>`;
  for (const c of d.proximas) {
    html += `<tr><td>${c.nombre}</td><td>${c.donante || 'No especificado'}</td><td>${c.fecha_limite}</td><td style="color:#cc0000"><strong>${c.dias_restantes}</strong></td><td>${c.monto || 'No especificado'}</td><td>${c.estado || 'en_análisis'}</td><td>Global</td><td><a href="${c.url}" style="color:#0066cc">Ver convocatoria</a></td></tr>`;
  }
  html += `</table>`;
}

html += `<br><small>FundingFlow · ${new Date().toLocaleString('es-ES')}</small>`;

return [{ json: {
  telegram_msg: msgTruncado,
  slack_text: slackText,
  gmail_html: html,
  asunto: `🔔 FundingFlow: ${d.urgentes.length} urgentes, ${d.proximas.length} próximas — ${d.fecha_reporte}`,
  total: d.total
}}];

return [{ json: {
  workflow_name: $workflow.name,
  node_name: $json.execution?.error?.node || 'Desconocido',
  error_message: $json.execution?.error?.message || 'Sin mensaje',
  timestamp: new Date().toISOString()
}}];
